<?php require_once 'db.php'; $u=require_login('admin'); verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ if(isset($_POST['add_table'])) pdo()->prepare('INSERT INTO library_tables(table_code,floor_no,zone,capacity,status) VALUES(?,?,?,?,?)')->execute([trim($_POST['table_code']),(int)$_POST['floor_no'],trim($_POST['zone']),1,$_POST['status']]); if(isset($_POST['add_librarian'])){ $rid=pdo()->query("SELECT id FROM roles WHERE name='librarian'")->fetchColumn(); pdo()->prepare('INSERT INTO users(role_id,name,email,password,status) VALUES(?,?,?,?,"active")')->execute([$rid,trim($_POST['name']),filter_var($_POST['email'],FILTER_VALIDATE_EMAIL),password_hash($_POST['password'],PASSWORD_DEFAULT)]); pdo()->prepare('INSERT INTO librarians(user_id,employee_code) VALUES(?,?)')->execute([pdo()->lastInsertId(),trim($_POST['employee_code'])]); } flash('Admin change saved.'); } $stats=['students'=>pdo()->query("SELECT COUNT(*) FROM users u JOIN roles r ON r.id=u.role_id WHERE r.name='student'")->fetchColumn(),'librarians'=>pdo()->query("SELECT COUNT(*) FROM users u JOIN roles r ON r.id=u.role_id WHERE r.name='librarian'")->fetchColumn(),'tables'=>pdo()->query('SELECT COUNT(*) FROM library_tables')->fetchColumn(),'revenue'=>pdo()->query("SELECT COALESCE(SUM(amount),0) FROM payments WHERE status='verified'")->fetchColumn()]; $bookings=pdo()->query('SELECT b.*,u.name,t.table_code,p.transaction_id FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id LEFT JOIN payments p ON p.booking_id=b.id ORDER BY b.id DESC LIMIT 20')->fetchAll(); app_header('Admin Dashboard'); ?><section class="stats"><?php foreach($stats as $k=>$v): ?><div class="card stat"><b><?=e(ucfirst($k))?></b><span><?=e($v)?></span></div><?php endforeach; ?></section><section class="grid2"><form method="post" class="card"><h2>Add Librarian</h2><?=csrf_field()?><input name="name" placeholder="Name" required><input name="email" type="email" placeholder="Email" required><input name="employee_code" placeholder="Employee code"><input name="password" type="password" minlength="8" placeholder="Password" required><button class="btn" name="add_librarian">Create</button></form><form method="post" class="card"><h2>Add Table</h2><?=csrf_field()?><input name="table_code" placeholder="Table code" required><input name="floor_no" type="number" value="1"><input name="zone" placeholder="Zone" value="A"><select name="status"><option>available</option><option>maintenance</option><option>inactive</option></select><button class="btn" name="add_table">Add table</button></form></section><section class="card wide"><h2>Bookings, payments and reports</h2><table><tr><th>ID</th><th>Student</th><th>Table</th><th>Amount</th><th>TXN</th><th>Status</th></tr><?php foreach($bookings as $b): ?><tr><td>#<?=e($b['id'])?></td><td><?=e($b['name'])?></td><td><?=e($b['table_code'])?></td><td>₹<?=e($b['amount'])?></td><td><?=e($b['transaction_id'])?></td><td><?=e($b['status'])?></td></tr><?php endforeach; ?></table></section><?php app_footer(); ?>
